SELECT COUNT(*)
FROM (
  SELECT DISTINCT A, B
  FROM Tbl_A
  WHERE C IN (
    SELECT D
    FROM   Tbl_B
    WHERE  UPPER(E) = 'E'
  )
) X;

SELECT COUNT(*)
FROM   DUAL
HAVING COUNT(*) > 4;

SELECT COUNT(*)
FROM DUAL
CONNECT BY LEVEL <= 2;

SELECT E.EMPNO
FROM   EMP E
WHERE  E.SAL > (SELECT AVG(SAL) FROM EMP WHERE DEPTNO = E.DEPTNO);

SELECT A, B, COUNT(*)
FROM   T
GROUP BY CUBE(A, B);

SELECT *
FROM   EMP
WHERE  SAL > ALL (SELECT SAL FROM EMP WHERE DEPTNO = 10);
